import React from 'react';
import type { CarryOverPreviewLineDto } from '../../services/kt/models';
import { formatVnd } from '../../utils/formatters';
import df from '../../styles/documentForm.module.css';
import erp from '../../styles/erpPage.module.css';

const CARRY_OVER_METHOD =
  'Tổng hợp số dư cuối năm từ số dư đầu + phát sinh đã ghi sổ, ghi vào OpeningBalances năm sau (không sinh phiếu kế toán — tương đương MM BC1/chuyển số dư).';

export interface CarryOverPreviewSectionProps {
  sourceYear: number;
  targetYear: number;
  lines: CarryOverPreviewLineDto[];
  loading?: boolean;
  testIdPrefix: string;
}

export const CarryOverPreviewSection: React.FC<CarryOverPreviewSectionProps> = ({
  sourceYear,
  targetYear,
  lines,
  loading,
  testIdPrefix,
}) => {
  if (loading) {
    return (
      <div className={df.section} data-testid={`${testIdPrefix}-preview-loading`}>
        <p style={{ margin: 0, fontSize: 13 }}>Đang tải preview số dư…</p>
      </div>
    );
  }

  const hasTt99Mapping = targetYear >= 2026 && lines.some(
    r => r.changeKind === 'Omitted' || r.changeKind === 'Renamed' || (r.mappingNote?.length ?? 0) > 0,
  );
  const transferable = lines.filter(r => r.changeKind !== 'Omitted');
  const omitted = lines.filter(r => r.changeKind === 'Omitted');
  const totalDebit = transferable.reduce((s, r) => s + r.debitBalance, 0);
  const totalCredit = transferable.reduce((s, r) => s + r.creditBalance, 0);

  return (
    <div data-testid={`${testIdPrefix}-preview`}>
      <div className={df.section}>
        <h2 className={df.sectionTitle}>Phương pháp chuyển số dư</h2>
        <p style={{ margin: 0, fontSize: 13, lineHeight: 1.5 }}>{CARRY_OVER_METHOD}</p>
        {hasTt99Mapping && (
          <p
            style={{ margin: '8px 0 0', fontSize: 12, color: 'var(--color-warning, #b45309)' }}
            data-testid={`${testIdPrefix}-preview-tt99-map-banner`}
          >
            Áp dụng map TT200→TT99 (tt200-tt99-garment): TK 611/631 không chuyển; TK đổi tên giữ mã, cập nhật danh mục TT99.
          </p>
        )}
        <p style={{ margin: '8px 0 0', fontSize: 12, color: 'var(--color-text-secondary, #6c757d)' }}>
          Preview: năm {sourceYear} → số dư đầu năm {targetYear} · {transferable.length} TK chuyển
          {omitted.length > 0 ? ` · ${omitted.length} TK bỏ qua` : ''}
        </p>
      </div>
      {transferable.length === 0 && omitted.length === 0 ? (
        <div className={df.section} data-testid={`${testIdPrefix}-preview-empty`}>
          <p style={{ margin: 0, fontSize: 13, color: 'var(--color-text-secondary, #6c757d)' }}>
            Không có số dư để chuyển cho năm {sourceYear}.
          </p>
        </div>
      ) : (
        <>
          {transferable.length > 0 && (
            <div className={df.section}>
              <h2 className={df.sectionTitle}>Preview số dư chuyển</h2>
              <div className={erp.tableWrapper}>
                <table className={erp.table}>
                  <thead>
                    <tr>
                      {hasTt99Mapping && <th>TK nguồn</th>}
                      <th>{hasTt99Mapping ? 'TK đích' : 'TK'}</th>
                      {hasTt99Mapping && <th>Ghi chú map</th>}
                      <th className={erp.colRight}>Dư Nợ</th>
                      <th className={erp.colRight}>Dư Có</th>
                    </tr>
                  </thead>
                  <tbody>
                    {transferable.map(row => {
                      const target = row.targetAccountCode ?? row.accountCode;
                      const source = row.sourceAccountCode ?? row.accountCode;
                      return (
                        <tr key={`${source}-${target}`} data-testid={`${testIdPrefix}-row-${target}`}>
                          {hasTt99Mapping && <td><code>{source}</code></td>}
                          <td><code>{target}</code></td>
                          {hasTt99Mapping && (
                            <td style={{ fontSize: 12 }}>
                              {row.changeKind === 'Renamed' ? row.mappingNote : '—'}
                            </td>
                          )}
                          <td className={erp.colRight}>{formatVnd(row.debitBalance)}</td>
                          <td className={erp.colRight}>{formatVnd(row.creditBalance)}</td>
                        </tr>
                      );
                    })}
                  </tbody>
                  <tfoot>
                    <tr>
                      <th colSpan={hasTt99Mapping ? 3 : 1}>Tổng</th>
                      <th className={erp.colRight}>{formatVnd(totalDebit)}</th>
                      <th className={erp.colRight}>{formatVnd(totalCredit)}</th>
                    </tr>
                  </tfoot>
                </table>
              </div>
            </div>
          )}
          {omitted.length > 0 && (
            <div className={df.section} data-testid={`${testIdPrefix}-preview-omitted`}>
              <h2 className={df.sectionTitle}>TK không chuyển (TT99)</h2>
              <div className={erp.tableWrapper}>
                <table className={erp.table}>
                  <thead>
                    <tr>
                      <th>TK</th>
                      <th>Lý do</th>
                      <th className={erp.colRight}>Dư Nợ (cuối năm)</th>
                      <th className={erp.colRight}>Dư Có (cuối năm)</th>
                    </tr>
                  </thead>
                  <tbody>
                    {omitted.map(row => (
                      <tr key={row.accountCode} data-testid={`${testIdPrefix}-omitted-${row.accountCode}`}>
                        <td><code>{row.accountCode}</code></td>
                        <td style={{ fontSize: 12 }}>{row.mappingNote}</td>
                        <td className={erp.colRight}>{formatVnd(row.debitBalance)}</td>
                        <td className={erp.colRight}>{formatVnd(row.creditBalance)}</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          )}
        </>
      )}
    </div>
  );
};
