import React, { useCallback, useEffect, useState } from 'react';
import { hasPermissionCode, usePeriodJobPermissions } from '../../../hooks/usePeriodJobPermissions';
import { PeriodActionPanel } from '../../../components/kt/PeriodActionPanel';
import { CarryOverPreviewSection } from '../../../components/kt/CarryOverPreviewSection';
import { ktService } from '../../../services/kt/ktService';
import type { CarryOverPreviewLineDto } from '../../../services/kt/models';
import { PERIOD_JOB_TYPES } from '../../../constants/periodJobTypes';
import { carryOverStatusLabel } from '../../../utils/periodProcessStatusLabel';

const CarryOverPreviewBlock: React.FC<{ year: number; testIdPrefix: string }> = ({
  year,
  testIdPrefix,
}) => {
  const [lines, setLines] = useState<CarryOverPreviewLineDto[]>([]);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    let cancelled = false;
    const t = setTimeout(() => {
      setLoading(true);
      ktService.getCarryOverPreview(year)
        .then(data => { if (!cancelled) setLines(data); })
        .catch(() => { if (!cancelled) setLines([]); })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [year]);

  return (
    <CarryOverPreviewSection
      sourceYear={year}
      targetYear={year + 1}
      lines={lines}
      loading={loading}
      testIdPrefix={testIdPrefix}
    />
  );
};

const ChuyenSoDuPage: React.FC = () => {
  const { canRun } = usePeriodJobPermissions('carry-over');
  void hasPermissionCode;
  const getStatus = useCallback(
    async (_m: number, y: number) => carryOverStatusLabel(await ktService.getCarryOverStatus(y)),
    [],
  );

  return (
    <PeriodActionPanel
      testIdPrefix="kt-chuyen-so-du"
      title="Chuyển số dư"
      icon="fa-random"
      description="Chuyển số dư cuối năm sang OpeningBalances năm mới — không sinh phiếu kế toán."
      showMonth={false}
      runLabel="Chuyển số dư"
      jobType={PERIOD_JOB_TYPES.CarryOver}
      gateMonth={12}
      jobStatusMonth={() => 0}
      getStatus={getStatus}
      onRun={(_m, y) => ktService.executeCarryOver(y)}
      runPermitted={canRun}
      renderExtra={({ year }) => (
        <CarryOverPreviewBlock year={year} testIdPrefix="kt-chuyen-so-du" />
      )}
    />
  );
};

export default ChuyenSoDuPage;
